func jobCardStyle(status string) string {
	base := "border:1px solid var(--border);border-radius:4px;margin-bottom:8px;overflow:hidden;"
	if status == "failed" {
		return base + "background:color-mix(in srgb,var(--surface) 94%,var(--commit) 6%)"
	}
	return base + "background:var(--surface)"
}

func jobSummaryStyle(status string) string {
	cursor := "pointer"
	if status == "queued" {
		cursor = "default"
	}
	return fmt.Sprintf("display:flex;align-items:flex-start;gap:10px;padding:12px 14px;cursor:%s;list-style:none", cursor)
}

func jobTypeLabel(jobType string) string {
	switch jobType {
	case "import.process":
		return "Import"
	case "entries.reprocess":
		return "Entries reprocess"
	case "account.analyze":
		return "Recalculate"
	default:
		return jobType
	}
}

func formatJobTimestamp(t time.Time) string {
	now := time.Now()
	today := now.Truncate(24 * time.Hour)
	yesterday := today.Add(-24 * time.Hour)
	ts := t.Local()
	timeStr := ts.Format("3:04 PM")
	day := ts.Truncate(24 * time.Hour)
	switch {
	case day.Equal(today):
		return timeStr
	case day.Equal(yesterday):
		return "Yesterday · " + timeStr
	default:
		return ts.Format("Jan 2") + " · " + timeStr
	}
}

type jobMeta struct {
	TransactionsImported   *int `json:"transactions_imported"`
	TransactionsSkippedDup *int `json:"transactions_skipped_duplicate"`
	EntriesProcessed       *int `json:"entries_processed"`
	SnapshotsWritten       *int `json:"snapshots_written"`
}

func jobSummaryLine(job store.ProcessingJob) string {
	switch job.Status {
	case "queued":
		return "Waiting to start"
	case "processing":
		return "Processing"
	case "failed":
		return "Failed"
	case "complete":
		var meta jobMeta
		_ = json.Unmarshal(job.Metadata, &meta)

		start := job.QueuedAt
		if job.StartedAt != nil {
			start = *job.StartedAt
		}
		var parts []string
		if job.CompletedAt != nil {
			elapsed := job.CompletedAt.Sub(start).Seconds()
			parts = append(parts, fmt.Sprintf("Completed in %.1fs", elapsed))
		}
		switch job.JobType {
		case "import.process":
			if meta.TransactionsImported != nil {
				parts = append(parts, fmt.Sprintf("%d transactions imported", *meta.TransactionsImported))
			}
			if meta.TransactionsSkippedDup != nil && *meta.TransactionsSkippedDup > 0 {
				parts = append(parts, fmt.Sprintf("%d duplicates skipped", *meta.TransactionsSkippedDup))
			}
		case "entries.reprocess":
			if meta.EntriesProcessed != nil {
				parts = append(parts, fmt.Sprintf("%d entries reprocessed", *meta.EntriesProcessed))
			}
		case "account.analyze":
			if meta.SnapshotsWritten != nil {
				parts = append(parts, fmt.Sprintf("%d snapshots written", *meta.SnapshotsWritten))
			}
		}
		if len(parts) == 0 {
			return "Complete"
		}
		result := parts[0]
		for _, p := range parts[1:] {
			result += " · " + p
		}
		return result
	}
	return ""
}

